const request = $items('Build AI Request')[0]?.json ?? {};
const ai = $items('Alephant Cost Control - Chat Completion')[0]?.json ?? {};
const log = $input.first().json ?? {};

const firstDefined = (...values) => values.find((value) => value !== undefined && value !== null && value !== '');
const nested = (...paths) => {
  for (const path of paths) {
    const value = path.split('.').reduce((current, key) => current?.[key], log);
    if (value !== undefined && value !== null && value !== '') return value;
  }
  return undefined;
};

const cost = firstDefined(
  nested('cost'),
  nested('totalCost'),
  nested('total_cost'),
  nested('amount'),
  nested('data.cost'),
  nested('data.totalCost'),
  nested('data.total_cost'),
  nested('billing.cost'),
  nested('billing.totalCost'),
);

const currency = firstDefined(
  nested('currency'),
  nested('data.currency'),
  nested('billing.currency'),
  'USD',
);

return [
  {
    json: {
      requestLogId: ai.requestLogId || ai.requestId,
      model: ai.model || request.model,
      prompt: request.prompt,
      responseText: ai.text,
      tokenUsageFromAiResponse: ai.usage,
      cost,
      currency,
      requestLog: log,
    },
  },
];
